INSERT INTO books (id, title, author_id, genre, year, description) VALUES (1, 'Kindred', 1, 'Science Fiction', 1979, 'A modern Black woman is transported back in time to the antebellum South where she must ensure the survival of a white slaveholder who is her ancestor.');
